function objectValuesAsRows(obj) {
  const keys = Object.keys(obj);
  if (!keys.length) return [];

  const isNumericKeyed = keys.every((k) => /^\d+$/.test(k));
  if (isNumericKeyed) {
    return keys
      .sort((a, b) => Number(a) - Number(b))
      .map((k) => obj[k]);
  }

  const arrayKeys = keys.filter((k) => Array.isArray(obj[k]));
  if (!arrayKeys.length) return [];

  const rowCount = Math.max(...arrayKeys.map((k) => obj[k].length));
  if (!rowCount || !Number.isFinite(rowCount)) return [];

  const scalarBroadcastAllowList = new Set([
    "uom",
    "unit",
    "per",
    "uqc",
    "cgst_rate",
    "sgst_rate",
    "igst_rate",
    "tax_rate",
    "gst_rate"
