  const hasMeaningfulData = Object.values(normalized).some((v) => v !== null && v !== "");
  return hasMeaningfulData ? normalized : null;
}

function dedupeLineItems(items) {
  const seen = new Set();
  const out = [];

  for (const row of items) {
    const key = JSON.stringify({
      description: row.description ?? "",
      hsn: row.hsn ?? "",
      quantity: row.quantity ?? "",
      rate: row.rate ?? "",
