const cgst_from_items = line_items.reduce((sum, row) => sum + (row.cgst ?? 0), 0);
const sgst_from_items = line_items.reduce((sum, row) => sum + (row.sgst ?? 0), 0);
const igst_from_items = line_items.reduce((sum, row) => sum + (row.igst ?? 0), 0);
const total_from_items = line_items.reduce((sum, row) => sum + (row.total_amount ?? row.taxable_amount ?? 0), 0);

const taxable_amount =
  toNumber(parsed.taxable_amount ?? parsed.subtotal_taxable ?? parsed.taxableValue) ??
  (line_items.length ? Number(taxable_from_items.toFixed(2)) : null);

const cgst =
  toNumber(parsed.cgst ?? parsed.total_cgst ?? parsed.cgst_amount) ??
  (line_items.length ? Number(cgst_from_items.toFixed(2)) : null);

const sgst =
  toNumber(parsed.sgst ?? parsed.total_sgst ?? parsed.sgst_amount) ??
  (line_items.length ? Number(sgst_from_items.toFixed(2)) : null);

const igst =
  toNumber(parsed.igst ?? parsed.total_igst ?? parsed.igst_amount) ??
  (line_items.length ? Number(igst_from_items.toFixed(2)) : null);

const round_off = toNumber(parsed.round_off ?? parsed.roundOff);
const tds = toNumber(parsed.tds);

const computed_total =
