    ? Number((taxable_amount + (cgst ?? 0) + (sgst ?? 0) + (igst ?? 0) + (round_off ?? 0) - (tds ?? 0)).toFixed(2))
    : null;

const total_amount =
  toNumber(parsed.total_amount ?? parsed.grand_total ?? parsed.invoice_total) ??
  (line_items.length ? Number(total_from_items.toFixed(2)) : null) ??
  computed_total;

const firstLine = line_items[0] ?? null;
const quantity_raw = sanitizeText(parsed.quantity_raw ?? firstLine?.quantity_raw ?? parsed.quantity);
