  }));

const normalizedTaxSummary = hsn_tax_summary;

const aggregatedTopLevelSignal = hasAggregatedColumns({
  description: parsed.description,
  hsn: parsed.hsn,
  quantity_raw: parsed.quantity_raw
});
const likelyLineItemLoss =
  (rawLineItemCandidates.length > 1 && line_items.length <= 1) ||
  (rawLineItemCandidates.length === 1 && expandedRawLineItemCandidates.length > 1 && line_items.length <= 1) ||
  (rawLineItemCandidates.length === 0 && aggregatedTopLevelSignal && line_items.length <= 1);
const normalizedInvoiceDate = normalizeDate(parsed.invoice_date ?? input.invoice_date);
const normalizedVendorName = sanitizeText(parsed.vendor_name ?? input.vendor_name);
const normalizedInvoiceNumber = sanitizeText(parsed.invoice_number ?? input.invoice_number);
const missingVoucherHeader =
  !normalizedVendorName ||
  !normalizedInvoiceNumber ||
  !normalizedInvoiceDate;

const review_required = true;

return [
  {
    json: {
      ...context,
      processed_at: new Date().toISOString(),
      vendor_name: normalizedVendorName,
vendor_gstin: sanitizeText(parsed.vendor_gstin ?? input.vendor_gstin),
buyer_name: sanitizeText(parsed.buyer_name ?? input.buyer_name),
buyer_gstin: sanitizeText(parsed.buyer_gstin ?? input.buyer_gstin),
