      debug_binary_fileName: item.binary?.data?.fileName || null,
      debug_binary_mimeType: item.binary?.data?.mimeType || null,
    },
    binary: item.binary
  }
];

const row = $input.first().json;

function isBlank(v) {
  return v === null || v === undefined || v === '';
}

function toNumber(v) {
  if (v === null || v === undefined || v === '') return null;
  if (typeof v === 'number') return Number.isFinite(v) ? v : null;
  const cleaned = String(v).replace(/,/g, '').trim();
  if (!cleaned) return null;
  const n = Number(cleaned);
  return Number.isNaN(n) ? null : n;
}

function validGSTIN(gstin) {
  if (!gstin || typeof gstin !== 'string') return false;
  return /^[0-9]{2}[A-Z]{5}[0-9]{4}[A-Z][A-Z0-9]Z[A-Z0-9]$/i.test(gstin.trim());
}

function normalizeLineItems(value) {
  if (!Array.isArray(value)) return [];
  return value
    .filter((row) => row && typeof row === 'object')
    .map((line) => {
      const item = line;
      return {
        description: item.description ?? null,
        hsn: item.hsn ?? null,
        quantity: toNumber(item.quantity),
        rate: toNumber(item.rate),
        taxable_amount: toNumber(item.taxable_amount),
        cgst: toNumber(item.cgst),
        sgst: toNumber(item.sgst),
        igst: toNumber(item.igst),
        total_amount: toNumber(item.total_amount)
      };
    });
}

const lowConfidenceFields = [];
const reviewWarnings = [];
let score = 1.0;

function flag(key, reason, penalty = 0.08) {
  lowConfidenceFields.push({ key, reason });
  score -= penalty;
}

function warn(key, reason) {
  reviewWarnings.push({ key, reason });
}

const lineItems = normalizeLineItems(row.line_items ?? row.lineItems);

const taxable = toNumber(row.taxable_amount);
const cgst = toNumber(row.cgst);
const sgst = toNumber(row.sgst);
const igst = toNumber(row.igst);
const roundOff = toNumber(row.round_off) || 0;
const tds = toNumber(row.tds) || 0;
const total = toNumber(row.total_amount);
const qty = toNumber(row.quantity);

const taxableFromItems = lineItems.reduce((sum, item) => sum + (item.taxable_amount || 0), 0);
const cgstFromItems = lineItems.reduce((sum, item) => sum + (item.cgst || 0), 0);
const sgstFromItems = lineItems.reduce((sum, item) => sum + (item.sgst || 0), 0);
const igstFromItems = lineItems.reduce((sum, item) => sum + (item.igst || 0), 0);

const hasInvoiceLevelTax =
  (cgst !== null && Math.abs(cgst) > 0.01) ||
  (sgst !== null && Math.abs(sgst) > 0.01) ||
  (igst !== null && Math.abs(igst) > 0.01);

const explicitRowTaxCount = lineItems.filter(
  (item) => item.cgst !== null || item.sgst !== null || item.igst !== null
).length;
const hasExplicitRowTax = explicitRowTaxCount > 0;

if (isBlank(row.vendor_name)) flag('vendor_name', 'Vendor name missing', 0.12);
if (isBlank(row.buyer_name)) flag('buyer_name', 'Buyer name missing', 0.10);
if (isBlank(row.invoice_number)) flag('invoice_number', 'Invoice number missing', 0.15);
if (isBlank(row.invoice_date)) flag('invoice_date', 'Invoice date missing or unclear', 0.12);
if (total === null) flag('total_amount', 'Total amount missing', 0.15);

if (!isBlank(row.vendor_gstin) && !validGSTIN(row.vendor_gstin)) {
  flag('vendor_gstin', 'Vendor GSTIN pattern invalid', 0.10);
}
if (!isBlank(row.buyer_gstin) && !validGSTIN(row.buyer_gstin)) {
  flag('buyer_gstin', 'Buyer GSTIN pattern invalid', 0.10);
}

if (!lineItems.length) {
  flag('line_items', 'Line items missing', 0.20);
  if (qty === null && isBlank(row.quantity_raw)) {
    flag('quantity', 'Quantity missing', 0.08);
  }
}

if (lineItems.length) {
  lineItems.forEach((item, index) => {
    if (isBlank(item.description)) flag('line_items[' + index + '].description', 'Line item description missing', 0.03);
    if (item.taxable_amount === null) flag('line_items[' + index + '].taxable_amount', 'Line taxable amount missing', 0.03);
    if (item.total_amount === null && item.taxable_amount === null) {
      flag('line_items[' + index + ']', 'Line amount missing', 0.03);
    }

    if (item.quantity !== null && item.rate !== null && item.taxable_amount !== null) {
      const expectedTaxable = item.quantity * item.rate;
      if (Math.abs(expectedTaxable - item.taxable_amount) > 5) {
        flag('line_items[' + index + '].taxable_amount', 'Line quantity x rate mismatch', 0.03);
      }
    }
  });

  if (taxable !== null && Math.abs(taxable - taxableFromItems) > 10) {
    flag('taxable_amount', 'Invoice taxable amount does not match line item sum', 0.10);
  }

  if (hasExplicitRowTax) {
    if (cgst !== null && Math.abs(cgst - cgstFromItems) > 10) {
      flag('cgst', 'Invoice CGST does not match line item sum', 0.08);
    }
    if (sgst !== null && Math.abs(sgst - sgstFromItems) > 10) {
      flag('sgst', 'Invoice SGST does not match line item sum', 0.08);
    }
    if (igst !== null && Math.abs(igst - igstFromItems) > 10) {
      flag('igst', 'Invoice IGST does not match line item sum', 0.08);
    }
  } else if (hasInvoiceLevelTax) {
    warn(
      'line_items.tax',
      'Invoice-level tax is present but row-level tax is not explicitly printed; row-level tax kept null as per extraction rule'
    );
  }
}

if (taxable === null && !lineItems.length) {
  flag('taxable_amount', 'Taxable amount missing', 0.15);
}

if (taxable !== null && total !== null) {
  const expectedTotal = Number((taxable + (cgst || 0) + (sgst || 0) + (igst || 0) + roundOff - tds).toFixed(2));
  if (Math.abs(expectedTotal - total) > 5) {
    flag('total_amount', 'Total amount does not match taxable + tax + round off - TDS', 0.12);
  }
}

score = Math.max(0, Math.min(1, Number(score.toFixed(2))));

const review_required = true;

return [
  {
    json: {
      ...row,
      confidence_score: score,
      review_required,
      low_confidence_fields: lowConfidenceFields,
      review_warnings: reviewWarnings
    }
  }
];

