  runtimeContext.originalPath ??
  source.originalPath ??
  source.originalFilePath ??
  source.filePath ??
  source.path ??
  source.body?.originalPath ??
  source.body?.originalFilePath ??
  source.body?.filePath ??
  source.body?.path ??
  '';

const mimeType =
  source.mimeType ??
  source.fileMimeType ??
  source.body?.mimeType ??
  data.mimeType ??
  null;

