parameters.jsCode:
return items.map(item => {
  const input = item.json ?? {};

  function escXml(value) {
    return String(value ?? '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/\"/g, '&quot;')
      .replace(/'/g, '&apos;');
  }

  function toNumber(value) {
    if (value === null || value === undefined || value === '') return null;
    if (typeof value === 'number') return Number.isFinite(value) ? value : null;
    const cleaned = String(value).replace(/,/g, '').trim();
    if (!cleaned) return null;
    const n = Number(cleaned);
    return Number.isFinite(n) ? n : null;
  }

  function decimalsOf(value) {
    const n = toNumber(value);
    if (n === null) return 0;
    const text = String(value ?? '').trim();
    const fraction = text.includes('.') ? text.split('.').pop() : '';
    if (!fraction) return 0;
    return Math.min(3, fraction.replace(/[^0-9]/g, '').length);
  }

  function normalizeUom(value) {
    const raw = String(value ?? '').trim().toUpperCase();
    if (!raw) return 'PCS';

    const map = {
      NOS: 'PCS',
      NO: 'PCS',
      PIECE: 'PCS',
      PIECES: 'PCS',
      PCS: 'PCS',
      KG: 'KGS',
      KGS: 'KGS',
      KILOGRAM: 'KGS',
      KILOGRAMS: 'KGS',
      GR: 'GRS',
      G: 'GRS',
      GRM: 'GRS',
      GRMS: 'GRS',
      GRAM: 'GRS',
      GRAMS: 'GRS',
      GRS: 'GRS'
    };

    return map[raw] ?? raw;
  }

  function normalizeLedgerName(value) {
    const s = String(value ?? '').trim();
    if (!s) return null;
    return s.replace(/\s+/g, ' ');
  }

  function noOpXml() {
    return [
      '<ENVELOPE>',
      '  <HEADER>',
      '    <TALLYREQUEST>Import Data</TALLYREQUEST>',
      '  </HEADER>',
      '  <BODY>',
      '    <IMPORTDATA>',
      '      <REQUESTDESC>',
      '        <REPORTNAME>All Masters</REPORTNAME>',
      '      </REQUESTDESC>',
      '      <REQUESTDATA>',
      '      </REQUESTDATA>',
      '    </IMPORTDATA>',
      '  </BODY>',
      '</ENVELOPE>'
    ].join('\n');
  }

  const idempotencySkip = Boolean(input.idempotency_skip);
  const normalizedPostingMode = String(input.posting_mode ?? input.postingMode ?? '').trim().toUpperCase();
  const usesInventoryMasters = normalizedPostingMode === 'INVENTORY_ITEMWISE';
  const vendor = String(input.vendor_name ?? input.vendorName ?? input.party_name ?? input.partyName ?? '').trim();
  const purchaseLedgerName = normalizeLedgerName(input.purchase_ledger_name ?? input.purchaseLedgerName ?? 'Purchase') || 'Purchase';

  const lineItems = Array.isArray(input.line_items ?? input.lineItems)
    ? (input.line_items ?? input.lineItems)
    : [];

  const stockMap = new Map();
  const unitDecimals = new Map([
    ['PCS', 0],
    ['KGS', 3],
    ['GRS', 3]
  ]);

  for (const row of lineItems) {
    if (!row || typeof row !== 'object') continue;
    const description = String(row.description ?? row.item_description ?? row.item ?? '').trim();
    if (!description) continue;
    const uom = normalizeUom(row.uom ?? row.unit ?? row.per ?? 'PCS');
    const qtyDecimals = Math.max(
      decimalsOf(row.quantity),
      decimalsOf(row.qty),
      decimalsOf(row.actual_qty),
      decimalsOf(row.billed_qty)
    );
    const previousDecimals = unitDecimals.get(uom) ?? 0;
    unitDecimals.set(uom, Math.max(previousDecimals, qtyDecimals));

    const key = `${description.toLowerCase()}|${uom}`;
    if (!stockMap.has(key)) {
      stockMap.set(key, {
        description,
        uom,
        hsn: String(row.hsn ?? row.hsn_sac ?? row.hsn_code ?? '').trim() || null
      });
    }
  }

  const uniqueStockItems = Array.from(stockMap.values());

  const stockGroupName = String(input.stock_group_name ?? input.stockGroupName ?? 'Workflow Items').trim() || 'Workflow Items';
  const stockGroupParent = String(input.stock_group_parent ?? input.stockGroupParent ?? 'Primary').trim() || 'Primary';

  const inputTaxLedgerNames = Array.isArray(input.tax_ledger_names)
    ? input.tax_ledger_names
    : [];

  const supportLedgerNames = Array.isArray(input.support_ledger_names)
    ? input.support_ledger_names
    : [];

  const taxLedgerNames = Array.from(
    new Set(
      inputTaxLedgerNames
        .map((name) => normalizeLedgerName(name))
        .filter((name) => Boolean(name))
    )
  );

  const normalizedSupportLedgers = Array.from(
    new Set(
      supportLedgerNames
        .map((name) => normalizeLedgerName(name))
        .filter((name) => Boolean(name))
    )
  );

  const unitMastersXml = Array.from(unitDecimals.entries())
    .map(([unit, decimals]) => {
      const escapedUnit = escXml(unit);
      const safeDecimals = Math.max(0, Math.min(3, Number(decimals) || 0));
      return [
        '        <TALLYMESSAGE>',
        `          <UNIT NAME="${escapedUnit}" ACTION="Create">`,
        `            <NAME>${escapedUnit}</NAME>`,
        '            <ISSIMPLEUNIT>Yes</ISSIMPLEUNIT>',
        `            <DECIMALPLACES>${safeDecimals}</DECIMALPLACES>`,
        '          </UNIT>',
        '        </TALLYMESSAGE>'
      ].join('\n');
    })
    .join('');

  const stockGroupXml = [
    '        <TALLYMESSAGE>',
    `          <STOCKGROUP NAME="${escXml(stockGroupName)}" ACTION="Create">`,
    `            <NAME>${escXml(stockGroupName)}</NAME>`,
    `            <PARENT>${escXml(stockGroupParent)}</PARENT>`,
    '          </STOCKGROUP>',
    '        </TALLYMESSAGE>'
  ].join('\n');

  const stockMastersXml = uniqueStockItems
    .map((stock) => {
      const name = escXml(stock.description);
      const unit = escXml(stock.uom);
      const hsn = stock.hsn ? escXml(stock.hsn) : '';
      return [
        '        <TALLYMESSAGE>',
        `          <STOCKITEM NAME="${name}" ACTION="Create">`,
        `            <NAME>${name}</NAME>`,
        `            <PARENT>${escXml(stockGroupName)}</PARENT>`,
        `            <BASEUNITS>${unit}</BASEUNITS>`,
        ...(hsn
          ? [
              '            <GSTDETAILS.LIST>',
              '              <APPLICABLEFROM>20010101</APPLICABLEFROM>',
              '              <CALCULATIONTYPE>On Value</CALCULATIONTYPE>',
              `              <HSNCODE>${hsn}</HSNCODE>`,
              '              <ISNONGSTGOODS>No</ISNONGSTGOODS>',
              '            </GSTDETAILS.LIST>'
            ]
          : []),
        '          </STOCKITEM>',
        '        </TALLYMESSAGE>'
      ].join('\n');
    })
    .join('');

  const taxLedgersXml = taxLedgerNames
    .map((ledgerName) => {
      const escaped = escXml(ledgerName);
      return [
        '        <TALLYMESSAGE>',
        `          <LEDGER NAME="${escaped}" ACTION="Create">`,
        `            <NAME>${escaped}</NAME>`,
        '            <PARENT>Duties &amp; Taxes</PARENT>',
        '            <ISBILLWISEON>No</ISBILLWISEON>',
        '          </LEDGER>',
        '        </TALLYMESSAGE>'
      ].join('\n');
    })
    .join('');

  const purchaseLedgerXml = purchaseLedgerName
    ? [
        '        <TALLYMESSAGE>',
        `          <LEDGER NAME="${escXml(purchaseLedgerName)}" ACTION="Create">`,
        `            <NAME>${escXml(purchaseLedgerName)}</NAME>`,
        '            <PARENT>Purchase Accounts</PARENT>',
        '            <ISBILLWISEON>No</ISBILLWISEON>',
        '          </LEDGER>',
        '        </TALLYMESSAGE>'
      ].join('\n')
    : '';

  const supportLedgersXml = normalizedSupportLedgers
    .filter((ledgerName) => ledgerName !== purchaseLedgerName)
    .map((ledgerName) => {
      const escaped = escXml(ledgerName);
      const parent = /^TDS\b/i.test(ledgerName) ? 'Current Assets' : 'Indirect Expenses';
      return [
        '        <TALLYMESSAGE>',
        `          <LEDGER NAME="${escaped}" ACTION="Create">`,
        `            <NAME>${escaped}</NAME>`,
        `            <PARENT>${escXml(parent)}</PARENT>`,
        '            <ISBILLWISEON>No</ISBILLWISEON>',
        '          </LEDGER>',
        '        </TALLYMESSAGE>'
      ].join('\n');
    })
    .join('');

  const vendorLedgerXml = vendor
    ? [
        '        <TALLYMESSAGE>',
        `          <LEDGER NAME="${escXml(vendor)}" ACTION="Create">`,
        `            <NAME>${escXml(vendor)}</NAME>`,
        '            <PARENT>Sundry Creditors</PARENT>',
        '            <ISBILLWISEON>Yes</ISBILLWISEON>',
        '          </LEDGER>',
        '        </TALLYMESSAGE>'
      ].join('\n')
    : '';

  const masterXml = idempotencySkip
    ? noOpXml()
    : [
        '<ENVELOPE>',
        '  <HEADER>',
        '    <TALLYREQUEST>Import Data</TALLYREQUEST>',
        '  </HEADER>',
        '  <BODY>',
        '    <IMPORTDATA>',
        '      <REQUESTDESC>',
        '        <REPORTNAME>All Masters</REPORTNAME>',
        '      </REQUESTDESC>',
        '      <REQUESTDATA>',
        `${vendorLedgerXml}${purchaseLedgerXml}${usesInventoryMasters ? `${unitMastersXml}${stockGroupXml}${stockMastersXml}` : ''}${taxLedgersXml}${supportLedgersXml}`,
        '      </REQUESTDATA>',
        '    </IMPORTDATA>',
        '  </BODY>',
        '</ENVELOPE>'
      ].join('\n').trim();

  return {
    json: {
      ...item.json,
      vendorNameExtracted: vendor,
      vendorLedgerXml: masterXml,
      masterXml,
      stock_group_name: stockGroupName,
      stock_group_parent: stockGroupParent
    }
  };
});

