    const text = value === undefined || value === null ? '' : String(value).trim();
    const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
    return uuidRegex.test(text) ? text : '';
  };
  const fromInvoiceObj = (obj) => toUuid(pick(
    obj?.invoiceId,
    obj?.invoice_id,
    obj?.data?.invoiceId,
    obj?.data?.invoice_id,
    obj?.body?.invoiceId,
