    ...$json,
    ...payload,
    tallyStatus,
    tallyLineError,
    tallyCreated,
    tallyAltered,
    tallyErrors,
    tallyExceptions,
    tallyBackendRunId: runId,
    tallyLogXml,
    tallyResponseRaw: JSON.stringify(payload)
  }
}];

const xml = $json.tallyLogXml || $json.data || $json.response || '';

return [
  {
    json: {
      ...$json
    },
    binary: {
      data: {
        data: Buffer.from(String(xml)).toString('base64'),
        mimeType: 'application/xml',
        fileName: `tally_response_${Date.now()}.xml`
      }
    }
  }
];

