return items.map(item => {
  const sourceJson = item.json ?? {};

  function pickNodeJson(candidates) {
    if (typeof $items !== 'function') return null;
    for (const name of candidates) {
      try {
        const rows = $items(name, 0, typeof $runIndex === 'number' ? $runIndex : 0);
        if (Array.isArray(rows) && rows.length > 0 && rows[0] && rows[0].json) {
          return rows[0].json;
        }
      } catch (_err) {
        // ignore
      }
    }
    return null;
  }

  const fallbackNode = pickNodeJson([
    'Code in JavaScript4',
    'Review node (HITL or Normal flow)',
    'Code in JavaScript',
  ]);

  const fallbackPayload =
    fallbackNode && typeof fallbackNode.body?.approvedData === 'object'
      ? fallbackNode.body.approvedData
      : (fallbackNode ?? {});

  const j = { ...fallbackPayload, ...sourceJson };

  for (const key of [
    'invoice_date', 'invoiceDate', 'invoice_number', 'invoiceNumber',
    'vendor_name', 'vendorName', 'purchase_ledger_name', 'purchaseLedgerName',
    'taxable_amount', 'cgst', 'sgst', 'igst', 'tds', 'round_off', 'total_amount',
    'description', 'hsn', 'quantity', 'rate', 'uom', 'unit', 'party_billwise'
  ]) {
    const current = j[key];
    const fallbackValue = fallbackPayload?.[key];
    const currentEmpty =
      current === null ||
      current === undefined ||
      (typeof current === 'string' && current.trim() === '');
    const fallbackHasValue =
      fallbackValue !== null &&
      fallbackValue !== undefined &&
      !(typeof fallbackValue === 'string' && fallbackValue.trim() === '');
    if (currentEmpty && fallbackHasValue) {
      j[key] = fallbackValue;
    }
  }

  if ((!Array.isArray(j.line_items) || j.line_items.length === 0) && Array.isArray(fallbackPayload?.line_items)) {
    j.line_items = fallbackPayload.line_items;
  }
  if ((!Array.isArray(j.lineItems) || j.lineItems.length === 0) && Array.isArray(fallbackPayload?.lineItems)) {
    j.lineItems = fallbackPayload.lineItems;
  }

  function toNumber(value) {
    if (value === null || value === undefined || value === '') return null;
    if (Array.isArray(value)) {
      for (const entry of value) {
        const n = toNumber(entry);
        if (n !== null) return n;
      }
      return null;
    }
    if (typeof value === 'number') return Number.isFinite(value) ? value : null;
    if (typeof value === 'object') {
      const candidate =
        value.amount ??
        value.value ??
        value.total ??
        value.taxable_amount ??
        value.tax ??
        value.raw ??
        null;
      if (candidate !== null) {
        return toNumber(candidate);
      }
      return null;
    }
    const cleaned = String(value)
      .replace(/,/g, '')
      .replace(/[\u20B9]/g, '')
      .replace(/\s+/g, '')
      .trim();
    if (!cleaned) return null;
    const n = Number(cleaned);
    return Number.isNaN(n) ? null : n;
  }

  function escXml(value) {
    return String(value ?? '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/\"/g, '&quot;')
      .replace(/'/g, '&apos;');
  }

  function normalizeRate(value) {
    const n = toNumber(value);
    if (n === null) return null;
    return Number(n.toFixed(3));
  }

  function normalizeUom(value) {
    const raw = String(value ?? '').trim().toUpperCase();
    if (!raw) return 'PCS';

    const map = {
      NOS: 'PCS',
      NO: 'PCS',
      PIECE: 'PCS',
      PIECES: 'PCS',
      PCS: 'PCS',
      KG: 'KGS',
      KGS: 'KGS',
      KILOGRAM: 'KGS',
      KILOGRAMS: 'KGS',
      GR: 'GRS',
      G: 'GRS',
      GRM: 'GRS',
      GRMS: 'GRS',
      GRAM: 'GRS',
      GRAMS: 'GRS',
      GRS: 'GRS'
    };

    return map[raw] ?? raw;
  }

  function cleanText(value) {
    if (value === null || value === undefined) return '';
    if (typeof value === 'string') return value.trim();
    if (typeof value === 'number' || typeof value === 'boolean') return String(value).trim();
    try {
      const serialized = JSON.stringify(value);
      if (serialized && serialized !== '{}' && serialized !== '[]') {
        return serialized.trim();
      }
    } catch (_err) {
      // ignore
    }
    const fallback = String(value).trim();
    return fallback === '[object Object]' ? '' : fallback;
  }

  function normalizeVoucherDate(value) {
    const raw = cleanText(value);
    if (!raw) return '';

    if (/^\d{8}$/.test(raw)) {
      if (raw.startsWith('19') || raw.startsWith('20')) {
        return raw;
      }
      const day = raw.slice(0, 2);
      const month = raw.slice(2, 4);
      const year = raw.slice(4, 8);
      return `${year}${month}${day}`;
    }

    if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) {
      return raw.replace(/-/g, '');
    }

    const dmy = raw.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})$/);
    if (dmy) {
      const day = dmy[1].padStart(2, '0');
      const month = dmy[2].padStart(2, '0');
      const year = dmy[3].length === 2 ? `20${dmy[3]}` : dmy[3];
      return `${year}${month}${day}`;
    }

    const ymd = raw.match(/^(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})$/);
    if (ymd) {
      return `${ymd[1]}${ymd[2].padStart(2, '0')}${ymd[3].padStart(2, '0')}`;
    }

    return '';
  }

  function noOpXml() {
    return [
      '<ENVELOPE>',
      '  <HEADER>',
      '    <TALLYREQUEST>Import Data</TALLYREQUEST>',
      '  </HEADER>',
      '  <BODY>',
      '    <IMPORTDATA>',
      '      <REQUESTDESC>',
      '        <REPORTNAME>All Masters</REPORTNAME>',
      '      </REQUESTDESC>',
      '      <REQUESTDATA>',
      '      </REQUESTDATA>',
      '    </IMPORTDATA>',
      '  </BODY>',
      '</ENVELOPE>'
    ].join('\n');
  }

  function normalizeLineItems(source) {
    if (!Array.isArray(source)) return [];

    return source
      .filter((row) => row && typeof row === 'object')
      .map((line, index) => {
        const li = line;
        const quantity = toNumber(li.quantity ?? li.qty ?? li.billed_qty ?? li.actual_qty);
        const rate = toNumber(li.rate ?? li.unit_rate ?? li.unitPrice);
        const taxable = toNumber(li.taxable_amount ?? li.taxable ?? li.taxable_value ?? li.amount);

        const cgst = toNumber(li.cgst ?? li.cgst_amount) ?? 0;
        const sgst = toNumber(li.sgst ?? li.sgst_amount) ?? 0;
        const igst = toNumber(li.igst ?? li.igst_amount) ?? 0;

        const inferredCgstRate = taxable ? Number(((cgst * 100) / taxable).toFixed(3)) : null;
        const inferredSgstRate = taxable ? Number(((sgst * 100) / taxable).toFixed(3)) : null;
        const inferredIgstRate = taxable ? Number(((igst * 100) / taxable).toFixed(3)) : null;

        const cgstRate = normalizeRate(li.cgst_rate ?? li.cgstRate) ?? inferredCgstRate;
        const sgstRate = normalizeRate(li.sgst_rate ?? li.sgstRate) ?? inferredSgstRate;
        const igstRate = normalizeRate(li.igst_rate ?? li.igstRate) ?? inferredIgstRate;

        const computedTotal =
          taxable !== null
            ? Number((taxable + cgst + sgst + igst).toFixed(2))
            : null;

        const total = toNumber(li.total_amount ?? li.total ?? li.line_total) ?? computedTotal;

        return {
          line_no: toNumber(li.line_no ?? li.lineNo ?? index + 1) ?? index + 1,
          description: String(li.description ?? li.item_description ?? li.item ?? `Item ${index + 1}`),
          hsn: li.hsn ?? li.hsn_sac ?? li.hsn_code ?? null,
          uom: normalizeUom(li.uom ?? li.unit ?? li.per ?? 'PCS'),
          quantity,
          rate,
          taxable_amount: taxable,
          cgst_rate: cgstRate,
          cgst,
          sgst_rate: sgstRate,
          sgst,
          igst_rate: igstRate,
          igst,
          total_amount: total
        };
      });
  }

  function formatQty(quantity, uom) {
    if (quantity === null) return `0 ${uom}`;
    return `${Number(quantity.toFixed(3))} ${uom}`;
  }

  function formatRate(rate, uom) {
    if (rate === null) return '';
    return `${Number(rate.toFixed(2))}/${uom}`;
  }

  function buildTaxBuckets(lines) {
    const buckets = new Map();

    const add = (type, rate, amount) => {
      const amt = Number((amount ?? 0).toFixed(2));
      if (!amt) return;
      const safeRate = Number((rate ?? 0).toFixed(3));
      const key = `${type}|${safeRate}`;
      if (!buckets.has(key)) {
        buckets.set(key, {
          type,
          rate: safeRate,
          amount: 0
        });
      }
      buckets.get(key).amount += amt;
    };

    for (const row of lines) {
      add('CGST', row.cgst_rate, row.cgst ?? 0);
      add('SGST', row.sgst_rate, row.sgst ?? 0);
      add('IGST', row.igst_rate, row.igst ?? 0);
    }

    return Array.from(buckets.values()).map((bucket) => ({
      ...bucket,
      amount: Number(bucket.amount.toFixed(2))
    }));
  }

  const deterministicTolerance = 1;
  const date = normalizeVoucherDate(j.invoice_date ?? j.invoiceDate);
  const vendor = cleanText(j.vendor_name ?? j.vendorName);
  const invoiceNumber = cleanText(j.invoice_number ?? j.invoiceNumber);
  const purchaseLedgerName = String(j.purchase_ledger_name ?? j.purchaseLedgerName ?? 'Purchase').trim() || 'Purchase';
  const partyBillwise = String(j.party_billwise ?? j.partyBillwise ?? 'yes').toLowerCase() !== 'no';

  let lineItems = normalizeLineItems(j.line_items ?? j.lineItems);

  const taxableFromItems = Number(lineItems.reduce((sum, row) => sum + (row.taxable_amount ?? 0), 0).toFixed(2));
  const cgstFromItems = Number(lineItems.reduce((sum, row) => sum + (row.cgst ?? 0), 0).toFixed(2));
  const sgstFromItems = Number(lineItems.reduce((sum, row) => sum + (row.sgst ?? 0), 0).toFixed(2));
  const igstFromItems = Number(lineItems.reduce((sum, row) => sum + (row.igst ?? 0), 0).toFixed(2));

  const taxableInput = toNumber(j.taxable_amount);
  const cgstInput = toNumber(j.cgst);
  const sgstInput = toNumber(j.sgst);
  const igstInput = toNumber(j.igst);
  const totalInput = toNumber(j.total_amount);

  const taxable = taxableInput ?? taxableFromItems;
  const cgst = cgstInput ?? cgstFromItems;
  const sgst = sgstInput ?? sgstFromItems;
  const igst = igstInput ?? igstFromItems;
  const tds = toNumber(j.tds) ?? 0;

  let roundOff = toNumber(j.round_off);
  if (roundOff === null && totalInput !== null) {
    roundOff = Number((totalInput - (taxable + cgst + sgst + igst - tds)).toFixed(2));
  }
  roundOff = roundOff ?? 0;

  const totalComputed = Number((taxable + cgst + sgst + igst + roundOff - tds).toFixed(2));
  const total = totalInput ?? totalComputed;

  if (!lineItems.length && taxable > 0) {
    lineItems = [
      {
        line_no: 1,
        description: String(j.description ?? 'Item 1'),
        hsn: j.hsn ?? null,
        uom: normalizeUom(j.uom ?? j.unit ?? 'PCS'),
        quantity: toNumber(j.quantity) ?? 1,
        rate: toNumber(j.rate) ?? taxable,
        taxable_amount: taxable,
        cgst_rate: null,
        cgst,
        sgst_rate: null,
        sgst,
        igst_rate: null,
        igst,
        total_amount: total
      }
    ];
  }

  const taxBuckets = buildTaxBuckets(lineItems);

  const taxLedgerEntries = [];
  const taxLedgerNames = [];

  if (taxBuckets.length) {
    for (const bucket of taxBuckets) {
      const rateText = Number(bucket.rate.toFixed(3)).toString();
      const ledgerName = `Input ${bucket.type} ${rateText}%`;
      taxLedgerNames.push(ledgerName);
      taxLedgerEntries.push([
        '            <ALLLEDGERENTRIES.LIST>',
        `              <LEDGERNAME>${escXml(ledgerName)}</LEDGERNAME>`,
        '              <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>',
        `              <AMOUNT>${bucket.amount.toFixed(2)}</AMOUNT>`,
        '            </ALLLEDGERENTRIES.LIST>'
      ].join('\n'));
    }
  } else {
    if (cgst) {
      taxLedgerNames.push('Input CGST');
      taxLedgerEntries.push([
        '            <ALLLEDGERENTRIES.LIST>',
        '              <LEDGERNAME>Input CGST</LEDGERNAME>',
        '              <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>',
        `              <AMOUNT>${cgst.toFixed(2)}</AMOUNT>`,
        '            </ALLLEDGERENTRIES.LIST>'
      ].join('\n'));
    }
    if (sgst) {
      taxLedgerNames.push('Input SGST');
      taxLedgerEntries.push([
        '            <ALLLEDGERENTRIES.LIST>',
        '              <LEDGERNAME>Input SGST</LEDGERNAME>',
        '              <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>',
        `              <AMOUNT>${sgst.toFixed(2)}</AMOUNT>`,
        '            </ALLLEDGERENTRIES.LIST>'
      ].join('\n'));
    }
    if (igst) {
      taxLedgerNames.push('Input IGST');
      taxLedgerEntries.push([
        '            <ALLLEDGERENTRIES.LIST>',
        '              <LEDGERNAME>Input IGST</LEDGERNAME>',
        '              <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>',
        `              <AMOUNT>${igst.toFixed(2)}</AMOUNT>`,
        '            </ALLLEDGERENTRIES.LIST>'
      ].join('\n'));
    }
  }

  const supportLedgerNames = [purchaseLedgerName];

  if (tds) {
    supportLedgerNames.push('TDS Receivable');
    taxLedgerEntries.push([
      '            <ALLLEDGERENTRIES.LIST>',
      '              <LEDGERNAME>TDS Receivable</LEDGERNAME>',
      '              <ISDEEMEDPOSITIVE>Yes</ISDEEMEDPOSITIVE>',
      `              <AMOUNT>-${tds.toFixed(2)}</AMOUNT>`,
      '            </ALLLEDGERENTRIES.LIST>'
    ].join('\n'));
  }

  if (roundOff) {
    supportLedgerNames.push('Round Off');
    const isPositive = roundOff >= 0;
    taxLedgerEntries.push([
      '            <ALLLEDGERENTRIES.LIST>',
      '              <LEDGERNAME>Round Off</LEDGERNAME>',
      `              <ISDEEMEDPOSITIVE>${isPositive ? 'No' : 'Yes'}</ISDEEMEDPOSITIVE>`,
      `              <AMOUNT>${roundOff.toFixed(2)}</AMOUNT>`,
      '            </ALLLEDGERENTRIES.LIST>'
    ].join('\n'));
  }

  const inventoryEntriesXml = lineItems
    .map((row) => {
      const stockName = escXml(row.description);
      const qtyText = escXml(formatQty(row.quantity, row.uom || 'PCS'));
      const rateText = escXml(formatRate(row.rate, row.uom || 'PCS'));
      const amount = Number((row.taxable_amount ?? row.total_amount ?? 0).toFixed(2));

      return [
        '            <ALLINVENTORYENTRIES.LIST>',
        `              <STOCKITEMNAME>${stockName}</STOCKITEMNAME>`,
        '              <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>',
        `              <RATE>${rateText}</RATE>`,
        `              <AMOUNT>${amount.toFixed(2)}</AMOUNT>`,
        `              <ACTUALQTY>${qtyText}</ACTUALQTY>`,
        `              <BILLEDQTY>${qtyText}</BILLEDQTY>`,
        '              <ACCOUNTINGALLOCATIONS.LIST>',
        `                <LEDGERNAME>${escXml(purchaseLedgerName)}</LEDGERNAME>`,
        '                <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>',
        `                <AMOUNT>${amount.toFixed(2)}</AMOUNT>`,
        '              </ACCOUNTINGALLOCATIONS.LIST>',
        '            </ALLINVENTORYENTRIES.LIST>'
      ].join('\n');
    })
    .join('');

  const narrationParts = [];
  if (j.description) narrationParts.push(String(j.description));
  if (lineItems.length) {
    narrationParts.push(
      lineItems
        .slice(0, 5)
        .map((row) => `${row.line_no}. ${row.description}${row.hsn ? ` [HSN ${row.hsn}]` : ''}`)
        .join(' | ')
    );
  }
  if (lineItems.length > 5) narrationParts.push(`+${lineItems.length - 5} more items`);

  const itemWiseMode = String(j.tally_item_voucher_mode ?? j.tallyItemVoucherMode ?? 'itemwise').toLowerCase();
  const useItemWiseVoucher = itemWiseMode === 'item' || itemWiseMode === 'itemwise' || itemWiseMode === 'inventory';

  const purchaseLedgerEntryXml = useItemWiseVoucher
    ? ''
    : [
        '            <ALLLEDGERENTRIES.LIST>',
        `              <LEDGERNAME>${escXml(purchaseLedgerName)}</LEDGERNAME>`,
        '              <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>',
        `              <AMOUNT>${taxable.toFixed(2)}</AMOUNT>`,
        '            </ALLLEDGERENTRIES.LIST>'
      ].join('\n');

  const billAllocationXml = partyBillwise
    ? [
        '              <BILLALLOCATIONS.LIST>',
        `                <NAME>${escXml(invoiceNumber || 'AUTO-REF')}</NAME>`,
        '                <BILLTYPE>New Ref</BILLTYPE>',
        `                <AMOUNT>-${total.toFixed(2)}</AMOUNT>`,
        '              </BILLALLOCATIONS.LIST>'
      ].join('\n')
    : '';

  const requestXml = [
    '<ENVELOPE>',
    '  <HEADER>',
    '    <TALLYREQUEST>Import Data</TALLYREQUEST>',
    '  </HEADER>',
    '  <BODY>',
    '    <IMPORTDATA>',
    '      <REQUESTDESC>',
    '        <REPORTNAME>Vouchers</REPORTNAME>',
    '      </REQUESTDESC>',
    '      <REQUESTDATA>',
    '        <TALLYMESSAGE>',
    '          <VOUCHER VCHTYPE="Purchase" ACTION="Create">',
    `            <DATE>${escXml(date)}</DATE>`,
    `            <VOUCHERNUMBER>${escXml(invoiceNumber)}</VOUCHERNUMBER>`,
    `            <REFERENCE>${escXml(invoiceNumber)}</REFERENCE>`,
    ...(useItemWiseVoucher
      ? [
          '            <ISINVOICE>Yes</ISINVOICE>',
          '            <PERSISTEDVIEW>Invoice Voucher View</PERSISTEDVIEW>'
        ]
      : []),
    `            <PARTYLEDGERNAME>${escXml(vendor)}</PARTYLEDGERNAME>`,
    `            <NARRATION>${escXml(narrationParts.join(' ; '))}</NARRATION>`,
    '            <ALLLEDGERENTRIES.LIST>',
    `              <LEDGERNAME>${escXml(vendor)}</LEDGERNAME>`,
    '              <ISDEEMEDPOSITIVE>Yes</ISDEEMEDPOSITIVE>',
    `              <AMOUNT>-${total.toFixed(2)}</AMOUNT>`,
    `${billAllocationXml}`,
    '            </ALLLEDGERENTRIES.LIST>',
    `${purchaseLedgerEntryXml}`,
    `${taxLedgerEntries.join('')}`,
    `${useItemWiseVoucher ? inventoryEntriesXml : ''}`,
    '          </VOUCHER>',
    '        </TALLYMESSAGE>',
    '      </REQUESTDATA>',
    '    </IMPORTDATA>',
    '  </BODY>',
    '</ENVELOPE>'
  ].join('\n').trim();

  const expectedTotalFromComponents = Number((taxable + cgst + sgst + igst + roundOff - tds).toFixed(2));
  const lineTotalFromItems = Number((taxableFromItems + cgstFromItems + sgstFromItems + igstFromItems + roundOff - tds).toFixed(2));

  const missingMandatory = [];

  if (!date) missingMandatory.push('invoice_date');
  if (!invoiceNumber) missingMandatory.push('invoice_number');
  if (!vendor) missingMandatory.push('vendor_name');
  if (lineItems.length === 0 && taxable <= 0 && total <= 0) missingMandatory.push('line_items_or_amounts');

  if (lineItems.length > 0 && taxableInput !== null && Math.abs(taxableInput - taxableFromItems) > deterministicTolerance) {
    missingMandatory.push('header_vs_line_taxable_mismatch');
  }
  if (lineItems.length > 0 && cgstInput !== null && Math.abs(cgstInput - cgstFromItems) > deterministicTolerance) {
    missingMandatory.push('header_vs_line_cgst_mismatch');
  }
  if (lineItems.length > 0 && sgstInput !== null && Math.abs(sgstInput - sgstFromItems) > deterministicTolerance) {
    missingMandatory.push('header_vs_line_sgst_mismatch');
  }
  if (lineItems.length > 0 && igstInput !== null && Math.abs(igstInput - igstFromItems) > deterministicTolerance) {
    missingMandatory.push('header_vs_line_igst_mismatch');
  }

  if (Math.abs(total - expectedTotalFromComponents) > deterministicTolerance) {
    missingMandatory.push('voucher_total_consistency');
  }

  if (lineItems.length > 0 && Math.abs(total - lineTotalFromItems) > Math.max(deterministicTolerance, Math.abs(lineTotalFromItems) * 0.001)) {
    missingMandatory.push('line_item_total_consistency');
  }

  const hasUpstreamSkipFlag = String(j.idempotency_skip ?? '').toLowerCase() === 'true';
  const matchedFile = String(j.idempotency_match_file ?? '').trim() || null;
  const matchedFileNormalized = matchedFile ? matchedFile.replace(/\\/g, '/').toLowerCase() : '';
  const matchedFileLooksSuccessful = matchedFileNormalized.includes('/success/');
  const upstreamIdempotencySkip = hasUpstreamSkipFlag || Boolean(matchedFile && matchedFileLooksSuccessful);

  const mandatorySkip = missingMandatory.length > 0;
  const idempotencySkip = upstreamIdempotencySkip || mandatorySkip;
  const idempotencyReason =
    String(j.idempotency_reason ?? '').trim() ||
    (mandatorySkip
      ? `Skipping Tally voucher import due to failed validations: ${missingMandatory.join(', ')}`
      : upstreamIdempotencySkip
        ? `Invoice ${invoiceNumber} already marked idempotent upstream`
        : null);

  return {
    json: {
      ...item.json,
      line_items: lineItems,
      purchase_ledger_name: purchaseLedgerName,
      tax_ledger_names: Array.from(new Set(taxLedgerNames)),
      support_ledger_names: Array.from(new Set(supportLedgerNames)),
      party_billwise: partyBillwise,
      idempotency_skip: idempotencySkip,
      idempotency_reason: idempotencyReason,
      idempotency_match_file: matchedFile,
      computed_totals: {
        taxable,
        cgst,
        sgst,
        igst,
        tds,
        round_off: roundOff,
        total,
        expected_total: expectedTotalFromComponents,
        line_total: lineTotalFromItems
      },
      tallyXml: idempotencySkip ? noOpXml() : requestXml,
      voucherRequestXml: idempotencySkip ? noOpXml() : requestXml
    }
  };
});

