    $json.runtimeContext?.invoiceMeta?.invoiceNumber,
    cfg.invoice_number, cfg.invoiceNumber,
    cfg.approvedData?.invoice_number, cfg.approvedData?.invoiceNumber,
    cfg.body?.invoice_number, cfg.body?.invoiceNumber,
    cfg.runtimeContext?.invoiceMeta?.invoiceNumber
  );

  const rawBinaryName = pick($binary?.data?.fileName, $binary?.data?.file_name);
  const binaryName = looksGeneratedTallyName(rawBinaryName) ? '' : rawBinaryName;

  const rawJsonName = pick($json.fileName, $json.file_name, $json.body?.fileName, $json.body?.file_name);
  const jsonName = looksGeneratedTallyName(rawJsonName) ? '' : rawJsonName;

  const srcPath = pick(
