    $json.approvedData?.originalPath, $json.approvedData?.originalFilePath, $json.approvedData?.filePath, $json.approvedData?.path,
    cfg.originalPath, cfg.originalFilePath, cfg.filePath, cfg.path
  );

  const fallbackBaseWithExt = (binaryName || jsonName || (srcPath ? srcPath.split(/[\/]/).pop() : '') || 'invoice').split(/[\/]/).pop() || 'invoice';
  const fallbackBase = fallbackBaseWithExt.replace(/\.(xlsx|xml|pdf|jpg|jpeg|png|webp)$/i, '');

  const hasBusinessName = Boolean(clean(vendorName) || clean(invoiceNumber));
  const businessBase = toToken(vendorName, 'vendor') + '_' + toToken(invoiceNumber, 'invoice');
  const base = hasBusinessName ? businessBase : toToken(fallbackBase, 'invoice');

  if (!dir) return '__MISSING_TENANT_EXCEPTION_DIR__/' + base + '_tally_response.xml';
  return dir.replace(/[\/]+$/, '') + '/' + base + '_tally_response.xml';
