parameters.jsonBody:
={{ (() => {
  const parseDate = (raw) => {
    if (raw === undefined || raw === null || raw === '') return null;
    const value = String(raw).trim();
    if (!value) return null;

    const monthMap = {
      jan: 1, january: 1, feb: 2, february: 2, mar: 3, march: 3,
      apr: 4, april: 4, may: 5, jun: 6, june: 6, jul: 7, july: 7,
      aug: 8, august: 8, sep: 9, sept: 9, september: 9,
      oct: 10, october: 10, nov: 11, november: 11, dec: 12, december: 12
    };

    const toYear = (y) => (String(y).length === 2 ? Number('20' + y) : Number(y));
    const toYmd = (y, m, d) =>
      String(y).padStart(4, '0') + '-' + String(m).padStart(2, '0') + '-' + String(d).padStart(2, '0');

    const ymdPrefix = value.match(/^(\d{4})-(\d{2})-(\d{2})(?:\b|T|\s|$)/);
    if (ymdPrefix) return toYmd(ymdPrefix[1], ymdPrefix[2], ymdPrefix[3]);

    const ymd = value.match(/^(\d{4})[./-](\d{1,2})[./-](\d{1,2})(?:\b.*)?$/);
    if (ymd) return toYmd(ymd[1], ymd[2], ymd[3]);

    const dmy = value.match(/^(\d{1,2})[./-](\d{1,2})[./-](\d{2,4})(?:\b.*)?$/);
    if (dmy) {
      const first = Number(dmy[1]);
      const second = Number(dmy[2]);
      const year = toYear(dmy[3]);
      const day = first > 12 && second <= 12 ? first : second > 12 && first <= 12 ? second : first;
      const month = first > 12 && second <= 12 ? second : second > 12 && first <= 12 ? first : second;
      return toYmd(year, month, day);
    }

    const dMonY = value.match(/^(\d{1,2})[\s./-]+([a-zA-Z]{3,9})[\s./-]+(\d{2,4})(?:\b.*)?$/);
    if (dMonY) {
      const day = Number(dMonY[1]);
      const month = monthMap[String(dMonY[2]).toLowerCase()];
      const year = toYear(dMonY[3]);
      if (month) return toYmd(year, month, day);
    }

    const monDY = value.match(/^([a-zA-Z]{3,9})[\s./-]+(\d{1,2}),?[\s./-]+(\d{2,4})(?:\b.*)?$/);
    if (monDY) {
      const month = monthMap[String(monDY[1]).toLowerCase()];
      const day = Number(monDY[2]);
      const year = toYear(monDY[3]);
      if (month) return toYmd(year, month, day);
    }

    const parsed = Date.parse(value);
    if (!Number.isNaN(parsed)) {
      const date = new Date(parsed);
      return toYmd(date.getFullYear(), date.getMonth() + 1, date.getDate());
    }

    return null;
  };

  const invoiceDate = parseDate($json.invoice_date || $json.invoiceDate || null);

  return JSON.stringify({
    extraction_status: (($json._meta && $json._meta.retryNeeded) ? 'PARTIAL' : 'SUCCESS'),
    retry_count: (($json._meta && $json._meta.retryNeeded) ? 1 : 0),
    raw_model_output: ($json.raw_model_output || $json._meta || {}),
    extracted_json: $json,
    normalized_fields: {
      invoice_number: ($json.invoice_number || $json.invoiceNumber || null),
      invoice_date: invoiceDate,
      party_name: ($json.vendor_name || $json.buyer_name || null),
      party_gstin: ($json.vendor_gstin || $json.buyer_gstin || null),
      currency: ($json.currency || 'INR'),
      subtotal: ($json.subtotal ?? $json.taxable_amount ?? null),
      taxable_amount: ($json.taxable_amount ?? null),
      cgst_amount: ($json.cgst ?? null),
      sgst_amount: ($json.sgst ?? null),
      igst_amount: ($json.igst ?? null),
      round_off_amount: ($json.round_off ?? null),
      total_amount: ($json.total_amount ?? null)
    },
    confidence_score: ($json.confidence_score ?? null),
    low_confidence_fields: ($json.low_confidence_fields || []),
    warnings: ($json.review_warnings || []),
    salvaged: Boolean($json._meta && $json._meta.retryNeeded),
    error_message: (($json._meta && $json._meta.retryNeeded) ? ($json._meta.error || 'Partial extraction salvaged') : null)
  });
})() }}

