// n8n Code node
// Returns OLD TOP-LEVEL extraction shape for downstream compatibility
// while preserving retry/debug info under _meta
// Also salvages partial extraction when JSON is truncated/broken

const input = $input.first().json;

// ---------- helpers ----------
function getByPath(obj, path, fallback = undefined) {
  try {
    return path.split(".").reduce((acc, key) => acc?.[key], obj) ?? fallback;
  } catch {
    return fallback;
  }
}

function extractText(payload) {
  if (typeof payload === "string") return payload;

  if (Array.isArray(payload)) {
    for (const item of payload) {
      const t = extractText(item);
      if (t) return t;
    }
  }

  const content = payload?.content;
  if (Array.isArray(content)) {
    const textParts = content
      .filter((c) => c && (c.type === "output_text" || typeof c.text === "string"))
      .map((c) => c.text || "")
      .filter(Boolean);

    if (textParts.length) return textParts.join("");
  }

  const candidates = [
    "output_text",
    "text",
    "message.content.0.text",
    "data.0.content.0.text",
    "body.data.0.content.0.text",
    "response.content.0.text",
    "response.output.0.content.0.text",
  ];

  for (const p of candidates) {
    const v = getByPath(payload, p);
    if (typeof v === "string" && v.trim()) return v;
  }

  return "";
}

function stripCodeFences(text) {
  return String(text || "")
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/\s*```$/i, "")
    .trim();
}

function extractJsonSubstring(text) {
  const s = String(text || "");
  const startObj = s.indexOf("{");
  const startArr = s.indexOf("[");
  let start = -1;

  if (startObj === -1) start = startArr;
  else if (startArr === -1) start = startObj;
  else start = Math.min(startObj, startArr);

  if (start === -1) return s.trim();
  return s.slice(start).trim();
}

function countUnescapedQuotes(s) {
  let count = 0;
  let escaped = false;
  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (escaped) {
      escaped = false;
      continue;
    }
    if (ch === "\\") {
      escaped = true;
      continue;
    }
    if (ch === '"') count++;
  }
  return count;
}

function trimToLastSafeBoundary(text) {
  const candidates = [
    text.lastIndexOf("},"),
    text.lastIndexOf('",'),
    text.lastIndexOf("null,"),
    text.lastIndexOf("],"),
    text.lastIndexOf("}"),
    text.lastIndexOf("]"),
  ].filter((n) => n >= 0);

  if (!candidates.length) return text;
  const cut = Math.max(...candidates);
  return text.slice(0, cut + 1);
}

function closeJsonStructures(text) {
  let result = String(text || "");

  if (countUnescapedQuotes(result) % 2 !== 0) {
    const lastQuote = result.lastIndexOf('"');
    if (lastQuote >= 0) {
      result = result.slice(0, lastQuote);
    }
  }

  result = trimToLastSafeBoundary(result).trim();

  let inString = false;
  let escaped = false;
  const stack = [];

  for (let i = 0; i < result.length; i++) {
    const ch = result[i];

    if (escaped) {
      escaped = false;
      continue;
    }
    if (ch === "\\") {
      escaped = true;
      continue;
    }
    if (ch === '"') {
      inString = !inString;
      continue;
    }
    if (inString) continue;

    if (ch === "{") stack.push("}");
    else if (ch === "[") stack.push("]");
    else if ((ch === "}" || ch === "]") && stack.length) {
      const expected = stack[stack.length - 1];
      if (ch === expected) stack.pop();
    }
  }

  result = result.replace(/,\s*$/, "");

  while (stack.length) {
    result += stack.pop();
  }

  return result;
}

function tryParseJson(text) {
  try {
    return { ok: true, data: JSON.parse(text), parsedText: text };
  } catch (err) {
    return { ok: false, error: err.message, parsedText: text };
  }
}

function repairJson(rawText) {
  let text = stripCodeFences(rawText);
  text = extractJsonSubstring(text);

  let parsed = tryParseJson(text);
  if (parsed.ok) return { ...parsed, repaired: false };

  let repaired = text
    .replace(/\u0000/g, "")
    .replace(/^\s*json\s*/i, "")
    .trim();

  parsed = tryParseJson(repaired);
  if (parsed.ok) return { ...parsed, repaired: false };

  repaired = closeJsonStructures(repaired);
  repaired = repaired.replace(/,\s*([}\]])/g, "$1");

  parsed = tryParseJson(repaired);
  if (parsed.ok) return { ...parsed, repaired: true };

  return {
    ok: false,
    error: parsed.error,
    repairedText: repaired,
  };
}

function detectIncomplete(payload, rawText) {
  const status =
    payload?.status ||
    payload?.response?.status ||
    payload?.data?.status ||
    null;

  const trimmed = String(rawText || "").trim();

  return {
    status,
    statusIncomplete: status === "incomplete",
    noClosingBrace: !!trimmed && !trimmed.endsWith("}") && !trimmed.endsWith("]"),
    endsMidKey: !!trimmed && /"[^"]*$/.test(trimmed),
    shortText: trimmed.length < 2,
  };
}

function normalizeTopLevel(data) {
  if (Array.isArray(data)) {
    const firstObj = data.find((x) => x && typeof x === "object" && !Array.isArray(x));
    return firstObj || {};
  }
  return data && typeof data === "object" ? data : {};
}

function ensureArrays(obj) {
  if (!Array.isArray(obj.line_items)) obj.line_items = [];
  if (!Array.isArray(obj.hsn_tax_summary)) obj.hsn_tax_summary = [];
  return obj;
}

// ---------- partial salvage helpers ----------
function extractPrimitiveValue(raw, key) {
  const escapedKey = key.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");

  const patterns = [
    new RegExp(`"${escapedKey}"\\s*:\\s*"((?:\\\\.|[^"\\\\])*)"`, "i"),
    new RegExp(`"${escapedKey}"\\s*:\\s*(-?\\d+(?:\\.\\d+)?)`, "i"),
    new RegExp(`"${escapedKey}"\\s*:\\s*(null|true|false)`, "i"),
  ];

  for (const pattern of patterns) {
    const match = raw.match(pattern);
    if (!match) continue;

    const value = match[1];
    if (value === "null") return null;
    if (value === "true") return true;
    if (value === "false") return false;
    if (/^-?\d+(\.\d+)?$/.test(value)) return Number(value);

    return value
      .replace(/\\"/g, '"')
      .replace(/\\\\/g, "\\")
      .replace(/\\n/g, "\n")
      .replace(/\\r/g, "\r")
      .replace(/\\t/g, "\t");
  }

  return undefined;
}

function extractObjectBlock(raw, key) {
  const startPattern = `"${key}"`;
  const keyIndex = raw.indexOf(startPattern);
  if (keyIndex === -1) return null;

  const colonIndex = raw.indexOf(":", keyIndex);
  if (colonIndex === -1) return null;

  let start = raw.indexOf("{", colonIndex);
  if (start === -1) return null;

  let inString = false;
  let escaped = false;
  let depth = 0;

  for (let i = start; i < raw.length; i++) {
    const ch = raw[i];

    if (escaped) {
      escaped = false;
      continue;
    }
    if (ch === "\\") {
      escaped = true;
      continue;
    }
    if (ch === '"') {
      inString = !inString;
      continue;
    }
    if (inString) continue;

    if (ch === "{") depth++;
    if (ch === "}") depth--;

    if (depth === 0) {
      return raw.slice(start, i + 1);
    }
  }

  return raw.slice(start); // truncated object
}

function salvageLineItems(raw) {
  const lineItemsKey = raw.indexOf('"line_items"');
  if (lineItemsKey === -1) return [];

  const arrStart = raw.indexOf("[", lineItemsKey);
  if (arrStart === -1) return [];

  const firstObjStart = raw.indexOf("{", arrStart);
  if (firstObjStart === -1) return [];

  // get first object only if truncated
  let inString = false;
  let escaped = false;
  let depth = 0;
  let foundAny = false;
  let block = "";

  for (let i = firstObjStart; i < raw.length; i++) {
    const ch = raw[i];
    block += ch;

    if (escaped) {
      escaped = false;
      continue;
    }
    if (ch === "\\") {
      escaped = true;
      continue;
    }
    if (ch === '"') {
      inString = !inString;
      continue;
    }
    if (inString) continue;

    if (ch === "{") {
      depth++;
      foundAny = true;
    } else if (ch === "}") {
      depth--;
      if (foundAny && depth === 0) {
        try {
          return [JSON.parse(block)];
        } catch {
          break;
        }
      }
    }
  }

  // truncated first line item: salvage known fields individually
  const partialItem = {};
  const itemFields = [
    "line_no",
    "description",
    "hsn",
    "quantity",
    "quantity_raw",
    "uom",
    "rate",
    "taxable_amount",
    "cgst",
    "cgst_raw",
    "sgst",
    "sgst_raw",
    "igst",
    "igst_raw",
    "total_amount",
  ];

  for (const field of itemFields) {
    const val = extractPrimitiveValue(block, field);
    if (val !== undefined) partialItem[field] = val;
  }

  return Object.keys(partialItem).length ? [partialItem] : [];
}

function salvagePartialExtraction(rawText) {
  const raw = extractJsonSubstring(stripCodeFences(rawText));
  const result = {};

  const topFields = [
    "vendor_name",
    "vendor_gstin",
    "buyer_name",
    "buyer_gstin",
    "invoice_number",
    "invoice_date",
    "state",
    "subtotal",
    "cgst",
    "sgst",
    "igst",
    "tds",
    "round_off",
    "total_amount",
  ];

  for (const field of topFields) {
    const val = extractPrimitiveValue(raw, field);
    if (val !== undefined) result[field] = val;
  }

  const hsnBlock = extractObjectBlock(raw, "hsn_tax_summary");
  result.line_items = salvageLineItems(raw);
  result.hsn_tax_summary = [];

  return ensureArrays(result);
}

// ---------- main ----------
const rawText = extractText(input);
const flags = detectIncomplete(input, rawText);
const repaired = repairJson(rawText);

if (repaired.ok) {
  const extraction = ensureArrays(normalizeTopLevel(repaired.data));

  return [
    {
      json: {
        ...extraction,
        _meta: {
          ok: true,
          retryNeeded: false,
          repaired: repaired.repaired,
          raw_status: flags.status,
          debug: {
            statusIncomplete: flags.statusIncomplete,
            noClosingBrace: flags.noClosingBrace,
            endsMidKey: flags.endsMidKey,
            rawTextPreview: rawText.slice(0, 1000),
          },
        },
      },
    },
  ];
}

// full parse failed -> salvage partial data instead of returning only _meta
const partialExtraction = salvagePartialExtraction(rawText);

return [
  {
    json: {
      ...partialExtraction,
      _meta: {
        ok: false,
        retryNeeded: true,
        repaired: false,
        raw_status: flags.status,
        error: "OpenAI did not return valid JSON; partial extraction salvaged",
        reason: {
          statusIncomplete: flags.statusIncomplete,
          noClosingBrace: flags.noClosingBrace,
          endsMidKey: flags.endsMidKey,
        },
        rawTextPreview: rawText.slice(0, 2000),
        repairedAttemptPreview: (repaired.repairedText || "").slice(0, 2000),
        retryPrompt:
          "Your previous response was truncated or invalid. Return only one minified JSON object matching the required schema. No markdown, no explanation, no code fences. If uncertain, use null. Do not stop mid-object.",
      },
    },
  },
];

